static void swapInt(int* a, int* b) { int t = *a; *a = *b; *b = t; }
int firstMissingPositive(int* nums, int n) {
    for (int i = 0; i < n; i++) {
        while (nums[i] >= 1 && nums[i] <= n && nums[nums[i]-1] != nums[i])
            swapInt(&nums[i], &nums[nums[i]-1]);
    }
    for (int i = 0; i < n; i++)
        if (nums[i] != i + 1) return i + 1;
    return n + 1;
}
